import{_ as s,C as a,o as n,c as h,E as e,a3 as d}from"./chunks/framework.CjmLrUhD.js";const p="/ecommerce-ops-vitepress/assets/image-test/image-01.png",c="/ecommerce-ops-vitepress/assets/image-test/image-02.png",m="/ecommerce-ops-vitepress/assets/image-test/image-03.png",k=JSON.parse('{"title":"测图 SOP 流程打造","description":"把主图测试、点击率判断和工具选择沉淀为标准流程，降低素材测试的不确定性。","frontmatter":{"title":"测图 SOP 流程打造","description":"把主图测试、点击率判断和工具选择沉淀为标准流程，降低素材测试的不确定性。"},"headers":[],"relativePath":"sop/image-test.md","filePath":"sop/image-test.md","lastUpdated":1783612931000}'),u={name:"sop/image-test.md"};function _(b,t,q,P,g,f){const o=a("DocHero"),i=a("ModuleFlow"),r=a("RelatedDocs"),l=a("ImageGallery");return n(),h("div",null,[e(o,{"module-id":"image-test","image-count":4,"section-count":16}),e(i,{"module-id":"image-test"}),e(r,{"module-id":"image-test"}),t[0]||(t[0]=d('<h1 id="测图-sop-流程打造执行手册" tabindex="-1">测图 SOP 流程打造执行手册 <a class="header-anchor" href="#测图-sop-流程打造执行手册" aria-label="Permalink to &quot;测图 SOP 流程打造执行手册&quot;">​</a></h1><h2 id="模块定位" tabindex="-1">模块定位 <a class="header-anchor" href="#模块定位" aria-label="Permalink to &quot;模块定位&quot;">​</a></h2><p>测图的目标是找到更容易获得点击的主图，而不是评价图片是否“好看”。运营要把图片变成可测试的变量：构图、卖点、利益点、场景、颜色、人物、价格表达和信任背书。每轮测试都要控制变量，最终用点击率和后续兴趣动作决定哪张图进入正式投放。</p><p>这套流程适合新品主图验证、爆款主图迭代、点击率长期低于行业参考、活动前素材准备等场景。</p><h2 id="开始前准备" tabindex="-1">开始前准备 <a class="header-anchor" href="#开始前准备" aria-label="Permalink to &quot;开始前准备&quot;">​</a></h2><p>测试前先准备 3-5 张图片，每张图只突出一个核心差异。例如一张强调卖点，一张强调场景，一张强调价格利益，一张强调人群痛点。不要同时改变太多元素，否则数据出来后无法判断到底是哪一个变量有效。</p><p>每张图片需要编号，记录设计思路、核心卖点、构图方式和适用人群。美工交付时也要保留源文件，便于后续修改。</p><h2 id="标准操作流程" tabindex="-1">标准操作流程 <a class="header-anchor" href="#标准操作流程" aria-label="Permalink to &quot;标准操作流程&quot;">​</a></h2><h3 id="_1-明确测图思路" tabindex="-1">1. 明确测图思路 <a class="header-anchor" href="#_1-明确测图思路" aria-label="Permalink to &quot;1. 明确测图思路&quot;">​</a></h3><p>测图只回答一个核心问题：同样流量条件下，哪张图更能让目标用户点击。为了保证判断成立，投放计划、人群、关键词、预算、出价尽量保持一致，避免图片之外的变量影响结果。</p><p>如果当前还不知道款是否值得做，先测款；如果款已经确认有潜力，但点击率弱，再进入测图。</p><h3 id="_2-设置预算和排期" tabindex="-1">2. 设置预算和排期 <a class="header-anchor" href="#_2-设置预算和排期" aria-label="Permalink to &quot;2. 设置预算和排期&quot;">​</a></h3><p>资料中给出的参考是“一张图 100 元预算，5 张图可以 500 元”。这个逻辑是为了保证每张图都有相对公平的曝光和点击机会。实际执行时要根据类目 PPC 调整，但原则不变：不要让某张图因为预算不足而没有样本。</p><p><img src="'+p+'" alt="测图预算与排期设置参考" loading="lazy"></p><h3 id="_3-控制人群变量" tabindex="-1">3. 控制人群变量 <a class="header-anchor" href="#_3-控制人群变量" aria-label="Permalink to &quot;3. 控制人群变量&quot;">​</a></h3><p>测图阶段一般不做人群细分，除非商品本身就是强人群产品。原始资料强调“人群不操作，除非是特殊人群”。这是为了避免图片数据被人群差异干扰。</p><p><img src="'+c+'" alt="测图人群设置参考" loading="lazy"></p><h3 id="_4-设置创意方式" tabindex="-1">4. 设置创意方式 <a class="header-anchor" href="#_4-设置创意方式" aria-label="Permalink to &quot;4. 设置创意方式&quot;">​</a></h3><p>纯测图时选择“仅商品主图”，不要打开会自动组合文案和素材的智能创意。否则系统可能展示了不同标题、素材或组合，最终点击率无法归因到主图本身。</p><p><img src="'+m+'" alt="仅商品主图设置参考" loading="lazy"></p><h3 id="_5-记录点击率和后续动作" tabindex="-1">5. 记录点击率和后续动作 <a class="header-anchor" href="#_5-记录点击率和后续动作" aria-label="Permalink to &quot;5. 记录点击率和后续动作&quot;">​</a></h3><p>每张图至少记录展现、点击、点击率、花费、PPC、收藏加购和成交。点击率是第一判断指标，但不是唯一指标。如果某张图点击率高但收藏加购明显差，说明它可能吸引了不准确的人群，需要谨慎使用。</p><p>测完后把图片分成三类：直接使用、保留优化、淘汰。直接使用的图进入主图或车图；保留优化的图提炼有效元素继续改；淘汰图记录失败原因，避免重复设计。</p><h2 id="数据判断标准" tabindex="-1">数据判断标准 <a class="header-anchor" href="#数据判断标准" aria-label="Permalink to &quot;数据判断标准&quot;">​</a></h2><p>测图判断要和行业点击率、历史主图、同批次图片对比。没有行业参考时，先看同轮测试内的相对表现。差异不明显时不要强行选胜出图，可以延长测试或重新设计变量。</p><p>如果所有图片点击率都低，问题可能不在单张图，而在产品卖点、价格、关键词或人群匹配。此时应回到点击率优化流程，重新收集行业创意和卖点表达。</p><h2 id="美工协作要求" tabindex="-1">美工协作要求 <a class="header-anchor" href="#美工协作要求" aria-label="Permalink to &quot;美工协作要求&quot;">​</a></h2><p>给美工的需求不能只写“做几张主图”。运营要给出图片编号、目标人群、核心卖点、参考图、需要突出和不能出现的元素。美工交付后，运营要检查每张图是否真的形成变量差异。</p><p>建议需求格式：产品链接、测试目标、参考竞品、核心卖点、图片数量、每张图方向、交付时间、尺寸要求、禁止事项。</p><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="为什么点击率高的图转化不好" tabindex="-1">为什么点击率高的图转化不好 <a class="header-anchor" href="#为什么点击率高的图转化不好" aria-label="Permalink to &quot;为什么点击率高的图转化不好&quot;">​</a></h3><p>可能是图片承诺过强，吸引了不精准点击；也可能是详情页没有承接图片卖点。需要检查图片卖点和详情页表达是否一致。</p><h3 id="是否需要每轮都测很多图" tabindex="-1">是否需要每轮都测很多图 <a class="header-anchor" href="#是否需要每轮都测很多图" aria-label="Permalink to &quot;是否需要每轮都测很多图&quot;">​</a></h3><p>不需要。图片太多会分散预算。优先测 3-5 张差异明显的图，得到方向后再小步迭代。</p><h3 id="能不能同时换标题、价格和主图" tabindex="-1">能不能同时换标题、价格和主图 <a class="header-anchor" href="#能不能同时换标题、价格和主图" aria-label="Permalink to &quot;能不能同时换标题、价格和主图&quot;">​</a></h3><p>不建议。测图阶段同时改多个变量，会让结果无法解释。除非目标是整体链接优化，而不是单独判断图片。</p><h2 id="复盘清单" tabindex="-1">复盘清单 <a class="header-anchor" href="#复盘清单" aria-label="Permalink to &quot;复盘清单&quot;">​</a></h2><ul><li>每张图片是否有明确变量</li><li>投放条件是否保持一致</li><li>每张图是否获得足够样本</li><li>是否记录点击率之外的收藏加购</li><li>是否沉淀可复用的设计结论</li></ul>',38)),e(l,{"module-id":"image-test"})])}const S=s(u,[["render",_]]);export{k as __pageData,S as default};
